}

package ConceptDesign {
  public import ScalarValues::*;
  public import RequirementsOnly::*;
  part def Balanced_Handheld_AirSense {
    attribute summary: String = "Compact consumer/prosumer handheld with integrated optical PM2.5 sensor, low‑power NDIR CO2 sensor, digital temperature/humidity combo sensor, active low-noise sampling (micro-fan), and an ESP32-class SoC providing both Wi‑Fi and Bluetooth.  Designed around a single PCB, 3.2' color touchscreen for local readout and menus, local data logging (ring buffer + microSD), and USB-C charging. Power management uses intermittent sampling and sensor duty‑cycling to guarantee an 8‑hour runtime on a single rechargeable 4000 mAh Li‑ion battery.";
  }
}

package RequirementsOnly {
  public import ScalarValues::*;
  requirement def RQ_001 { text = "Design a handheld environmental monitor that measures PM2.5, CO2, temperature, and humidity, runs 8 hours on a rechargeable battery, and syncs data via Wi-Fi or Bluetooth."; }
}

package ConceptDesign {
  public import ScalarValues::*;
  public import RequirementsOnly::*;
  part def Rugged_Field_Pro_Monitor {
    attribute summary: String = "Durable, mission-oriented handheld for professionals and field technicians. Modular sensor cartridges allow use of high-accuracy NDIR CO2 cartridges and a high-flow optical PM2.5 module with replaceable pump. Built with a larger swappable battery pack (10,000 mAh) to support continuous active sampling for 8+ hours even under high sampling rates. Primary connectivity via Wi‑Fi for direct upload to enterprise servers; BLE used for local handset control. Includes hardened IP65 enclosure, glove-friendly interface (physical buttons + sunlight-readable monochrome LCD), GPS timestamping and optional rugged cradle for vehicle use.";
  }
}

package RequirementsOnly {
  public import ScalarValues::*;
  requirement def RQ_001 { text = "Design a handheld environmental monitor that measures PM2.5, CO2, temperature, and humidity, runs 8 hours on a rechargeable battery, and syncs data via Wi-Fi or Bluetooth."; }
}

package ConceptDesign {
  public import ScalarValues::*;
  public import RequirementsOnly::*;
  part def PocketSync_Sensor_Dongle {
    attribute summary: String = "Ultra-portable pocket sensor that offloads heavy UI and cloud sync to the user's smartphone. Small enclosure contains a low-power optical PM2.5 sensor, a compact low-power NDIR CO2 sensor (or CO2 module with ABC algorithm), and a combined T/H sensor. Primary sync over Bluetooth Low Energy to the phone app; optional direct Wi‑Fi upload through built-in Wi‑Fi hotspot when phone not present. Minimal local interface (multi-color status LED + one button). Runtime tailored to 8 hours with a 3000 mAh battery by aggressive power optimization (intermittent sampling, sensor sleep modes) and by delegating long-term storage/visualization to the phone.";
  }
}

